+        return 2;
+    }
+
+    var exit_code: u8 = 0;
+
+    for (args) |filename| {
+        _ = compile(allocator, filename, null, null, true, -1, null) catch |err| {
+            std.debug.print("Error compiling {s}: {}\n", .{ filename, err });
